     1→// Eval-specific generator functions for the evaluation domain.
     2→// Each function returns a TypeScript (or Python/YAML) source string
     3→// that gets written into the generated project.
     4→
     5→export function generateEvalExecutor(): string {
     6→  return `import * as fs from 'fs';
     7→import * as path from 'path';
     8→import * as crypto from 'crypto';
     9→import chalk from 'chalk';
    10→import ora from 'ora';
    11→import { SpecParser, type EvalSpec } from './spec-parser.js';
    12→import { TaskRegistry, createDefaultRegistry } from './task-registry.js';
    13→import { ResultsManager } from './results-manager.js';
    14→import { ReportGenerator } from './report-generator.js';
    15→
    16→export interface EvalContext {
    17→  runId: string;
    18→  targetDir: string;
    19→  workingDir: string;
    20→  verbose: boolean;
    21→  apiKey?: string;
    22→}
    23→
    24→export class EvalExecutor {
    25→  private specParser: SpecParser;
    26→  private registry: TaskRegistry;
    27→  private resultsManager: ResultsManager;
    28→  private reportGenerator: ReportGenerator;
    29→  private verbose: boolean;
    30→  private apiKey?: string;
    31→
    32→  constructor(options: { verbose?: boolean; apiKey?: string } = {}) {
    33→    this.specParser = new SpecParser();
    34→    this.registry = createDefaultRegistry();
    35→    this.resultsManager = new ResultsManager();
    36→    this.reportGenerator = new ReportGenerator();
    37→    this.verbose = options.verbose || false;
    38→    this.apiKey = options.apiKey;
    39→  }
    40→
    41→  async init(specPath: string): Promise<string> {
    42→    const spinner = ora('Parsing eval spec...').start();
    43→
    44→    try {
    45→      // Parse and validate the spec
    46→      const spec = this.specParser.parse(specPath);
    47→      spinner.text = 'Creating eval run...';
    48→
    49→      // Resolve target directory
    50→      let targetDir: string;
    51→      if (spec.target.repo) {
    52→        if (spec.target.repo.startsWith('http') || spec.target.repo.startsWith('git@')) {
    53→          // Git clone
    54→          const { execSync } = await import('child_process');
    55→          const tmpDir = path.join('.eval-runs', 'targets', spec.name);
    56→          fs.mkdirSync(tmpDir, { recursive: true });
    57→          execSync(\`git clone \${spec.target.repo} \${tmpDir}\`, { stdio: 'pipe' });
    58→          if (spec.target.ref) {
    59→            execSync(\`git checkout \${spec.target.ref}\`, { cwd: tmpDir, stdio: 'pipe' });
    60→          }
    61→          targetDir = path.resolve(tmpDir);
    62→        } else {
    63→          targetDir = path.resolve(spec.target.repo);
    64→        }
    65→      } else {
    66→        targetDir = process.cwd();
    67→      }
    68→
    69→      if (!fs.existsSync(targetDir)) {
    70→        throw new Error(\`Target directory not found: \${targetDir}\`);
    71→      }
    72→
    73→      // Create run
    74→      const runId = this.resultsManager.createRun();
    75→
    76→      // Compute spec hash for reproducibility
    77→      const specContent = fs.readFileSync(specPath, 'utf-8');
    78→      const specHash = crypto.createHash('sha256').update(specContent).digest('hex').slice(0, 16);
    79→
    80→      // Check Docker availability
    81→      let dockerAvailable = false;
    82→      try {
    83→        const { execSync } = await import('child_process');
    84→        execSync('docker info', { stdio: 'pipe' });
    85→        dockerAvailable = true;
    86→      } catch {}
    87→
    88→      // Write manifest
    89→      const manifest = {
    90→        runId,
    91→        specName: spec.name,
    92→        specVersion: spec.version,
    93→        specHash,
    94→        startedAt: new Date().toISOString(),
    95→        status: 'initialized' as const,
    96→        target: {
    97→          repo: spec.target.repo,
    98→          ref: spec.target.ref,
    99→          dataset: spec.target.dataset,
   100→          resolvedPath: targetDir,
   101→        },
   102→        environment: {
   103→          node: process.version,
   104→          platform: process.platform,
   105→          arch: process.arch,
   106→          docker: dockerAvailable,
   107→        },
   108→        taskCount: spec.tasks.length,
   109→        taskIds: spec.tasks.map(t => t.id),
   110→      };
   111→
   112→      this.resultsManager.writeManifest(runId, manifest);
   113→
   114→      spinner.succeed(\`Eval run initialized: \${chalk.cyan(runId)}\`);
   115→      console.log(chalk.gray(\`  Spec: \${spec.name} v\${spec.version}\`));
   116→      console.log(chalk.gray(\`  Target: \${targetDir}\`));
   117→      console.log(chalk.gray(\`  Tasks: \${spec.tasks.length} (\${spec.tasks.map(t => t.id).join(', ')})\`));
   118→      console.log(chalk.gray(\`  Spec hash: \${specHash}\`));
   119→
   120→      return runId;
   121→    } catch (error) {
   122→      spinner.fail('Failed to initialize eval run');
   123→      throw error;
   124→    }
   125→  }
   126→
   127→  async run(runIdOrSpec?: string): Promise<void> {
   128→    let runId: string;
   129→
   130→    if (runIdOrSpec && runIdOrSpec.endsWith('.yaml') || runIdOrSpec?.endsWith('.yml') || runIdOrSpec?.endsWith('.json')) {
   131→      // Initialize from spec file first
   132→      runId = await this.init(runIdOrSpec);
   133→    } else if (runIdOrSpec) {
   134→      runId = runIdOrSpec;
   135→    } else {
   136→      // Find latest run
   137→      const runs = this.resultsManager.listRuns();
   138→      if (runs.length === 0) {
   139→        throw new Error('No eval runs found. Use /eval-init <spec> first.');
   140→      }
   141→      runId = runs[0].runId;
   142→    }
   143→
   144→    const manifest = this.resultsManager.readManifest(runId);
   145→    if (!manifest) {
   146→      throw new Error(\`Run not found: \${runId}\`);
   147→    }
   148→
   149→    // Re-parse spec to get task definitions
   150→    // Find the spec file by searching eval-specs/
   151→    const specDir = 'eval-specs';
   152→    let spec: EvalSpec | null = null;
   153→    if (fs.existsSync(specDir)) {
   154→      const specFiles = fs.readdirSync(specDir).filter(f => f.endsWith('.yaml') || f.endsWith('.yml') || f.endsWith('.json'));
   155→      for (const f of specFiles) {
   156→        try {
   157→          const parsed = this.specParser.parse(path.join(specDir, f));
   158→          if (parsed.name === manifest.specName) {
   159→            spec = parsed;
   160→            break;
   161→          }
   162→        } catch {}
   163→      }
   164→    }
   165→
   166→    if (!spec) {
   167→      throw new Error(\`Could not find spec "\${manifest.specName}" in eval-specs/\`);
   168→    }
   169→
   170→    // Update manifest status
   171→    manifest.status = 'running';
   172→    this.resultsManager.writeManifest(runId, manifest);
   173→
   174→    console.log(chalk.cyan.bold(\`\\nRunning eval: \${spec.name} v\${spec.version}\`));
   175→    console.log(chalk.gray(\`Run ID: \${runId}\\n\`));
   176→
   177→    const ctx: EvalContext = {
   178→      runId,
   179→      targetDir: manifest.target.resolvedPath,
   180→      workingDir: process.cwd(),
   181→      verbose: this.verbose,
   182→      apiKey: this.apiKey,
   183→    };
   184→
   185→    let totalCost = 0;
   186→    let hasFailure = false;
   187→
   188→    for (const task of spec.tasks) {
   189→      const taskSpinner = ora(\`Running task: \${task.id} (\${task.type})\`).start();
   190→
   191→      try {
   192→        const handler = this.registry.get(task.type);
   193→        if (!handler) {
   194→          const result = {
   195→            taskId: task.id,
   196→            type: task.type,
   197→            status: 'error' as const,
   198→            startedAt: new Date().toISOString(),
   199→            completedAt: new Date().toISOString(),
   200→            durationMs: 0,
   201→            metrics: {},
   202→            criteria: {},
   203→            error: \`Unknown task type: \${task.type}. Register a handler with registry.register().\`,
   204→          };
   205→          this.resultsManager.writeTaskResult(runId, task.id, result);
   206→          taskSpinner.warn(\`Task \${task.id}: unknown type "\${task.type}"\`);
   207→          hasFailure = true;
   208→          continue;
   209→        }
   210→
   211→        const result = await handler.execute(task, ctx);
   212→        this.resultsManager.writeTaskResult(runId, task.id, result);
   213→
   214→        if (result.estimatedCost) {
   215→          totalCost += result.estimatedCost.amount;
   216→        }
   217→
   218→        if (result.status === 'pass') {
   219→          taskSpinner.succeed(\`Task \${task.id}: \${chalk.green('PASS')} (\${result.durationMs}ms)\`);
   220→        } else if (result.status === 'fail') {
   221→          taskSpinner.fail(\`Task \${task.id}: \${chalk.red('FAIL')} (\${result.durationMs}ms)\`);
   222→          hasFailure = true;
   223→        } else if (result.status === 'skip') {
   224→          taskSpinner.info(\`Task \${task.id}: \${chalk.yellow('SKIP')} - \${result.error || 'skipped'}\`);
   225→        } else {
   226→          taskSpinner.fail(\`Task \${task.id}: \${chalk.red('ERROR')} - \${result.error}\`);
   227→          hasFailure = true;
   228→        }
   229→
   230→        // Show metrics in verbose mode
   231→        if (this.verbose && Object.keys(result.metrics).length > 0) {
   232→          for (const [key, value] of Object.entries(result.metrics)) {
   233→            console.log(chalk.gray(\`    \${key}: \${value}\`));
   234→          }
   235→        }
   236→
   237→        // Show cost if applicable
   238→        if (result.estimatedCost) {
   239→          console.log(chalk.gray(\`    Cost: $\${result.estimatedCost.amount.toFixed(4)}\`));
   240→        }
   241→      } catch (error) {
   242→        const result = {
   243→          taskId: task.id,
   244→          type: task.type,
   245→          status: 'error' as const,
   246→          startedAt: new Date().toISOString(),
   247→          completedAt: new Date().toISOString(),
   248→          durationMs: 0,
   249→          metrics: {},
   250→          criteria: {},
   251→          error: error instanceof Error ? error.message : String(error),
   252→        };
   253→        this.resultsManager.writeTaskResult(runId, task.id, result);
   254→        taskSpinner.fail(\`Task \${task.id}: \${chalk.red('ERROR')} - \${result.error}\`);
   255→        hasFailure = true;
   256→      }
   257→    }
   258→
   259→    // Update manifest
   260→    manifest.status = hasFailure ? 'failed' : 'completed';
   261→    manifest.completedAt = new Date().toISOString();
   262→    if (totalCost > 0) {
   263→      manifest.totalCost = { amount: totalCost, currency: 'USD' };
   264→    }
   265→    this.resultsManager.writeManifest(runId, manifest);
   266→
   267→    console.log(chalk.cyan(\`\\nEval run \${manifest.status}: \${runId}\`));
   268→    if (totalCost > 0) {
   269→      console.log(chalk.gray(\`Total cost: $\${totalCost.toFixed(4)}\`));
   270→    }
   271→  }
   272→
   273→  async report(runId?: string): Promise<void> {
   274→    if (!runId) {
   275→      const runs = this.resultsManager.listRuns();
   276→      if (runs.length === 0) {
   277→        throw new Error('No eval runs found.');
   278→      }
   279→      runId = runs[0].runId;
   280→    }
   281→
   282→    const manifest = this.resultsManager.readManifest(runId);
   283→    if (!manifest) {
   284→      throw new Error(\`Run not found: \${runId}\`);
   285→    }
   286→
   287→    const taskResults = this.resultsManager.readAllTaskResults(runId);
   288→
   289→    // Find baselines from spec if available
   290→    let baselines: Record<string, number> | undefined;
   291→    const specDir = 'eval-specs';
   292→    if (fs.existsSync(specDir)) {
   293→      const specFiles = fs.readdirSync(specDir).filter(f => f.endsWith('.yaml') || f.endsWith('.yml') || f.endsWith('.json'));
   294→      for (const f of specFiles) {
   295→        try {
   296→          const parsed = this.specParser.parse(path.join(specDir, f));
   297→          if (parsed.name === manifest.specName && parsed.baselines) {
   298→            baselines = parsed.baselines;
   299→            break;
   300→          }
   301→        } catch {}
   302→      }
   303→    }
   304→
   305→    const summaryJson = this.reportGenerator.generateJSON(manifest, taskResults, baselines);
   306→    const summaryMd = this.reportGenerator.generateMarkdown(manifest, taskResults, baselines);
   307→
   308→    this.resultsManager.writeSummary(runId, summaryJson, summaryMd);
   309→
   310→    // Print the markdown report to console
   311→    console.log(summaryMd);
   312→    console.log(chalk.gray(\`\\nReport saved to .eval-runs/\${runId}/summary.json and summary.md\`));
   313→  }
   314→
   315→  async compare(runId1: string, runId2: string): Promise<void> {
   316→    const manifest1 = this.resultsManager.readManifest(runId1);
   317→    const manifest2 = this.resultsManager.readManifest(runId2);
   318→
   319→    if (!manifest1 || !manifest2) {
   320→      throw new Error('One or both runs not found.');
   321→    }
   322→
   323→    const results1 = this.resultsManager.readAllTaskResults(runId1);
   324→    const results2 = this.resultsManager.readAllTaskResults(runId2);
   325→
   326→    const summary1 = this.reportGenerator.generateJSON(manifest1, results1);
   327→    const summary2 = this.reportGenerator.generateJSON(manifest2, results2);
   328→
   329→    // Build comparison table
   330→    console.log(chalk.cyan.bold('\\nEval Comparison'));
   331→    console.log(chalk.gray(\`Run A: \${runId1}\`));
   332→    console.log(chalk.gray(\`Run B: \${runId2}\\n\`));
   333→
   334→    // Header
   335→    const header = \`\${'Task'.padEnd(25)} \${'Status A'.padEnd(10)} \${'Status B'.padEnd(10)} \${'Delta'.padEnd(15)} \${'Notes'}\`;
   336→    console.log(chalk.white.bold(header));
   337→    console.log(chalk.gray('-'.repeat(80)));
   338→
   339→    const s1Tasks = new Map(summary1.tasks.map(t => [t.taskId, t]));
   340→    const s2Tasks = new Map(summary2.tasks.map(t => [t.taskId, t]));
   341→
   342→    const allTaskIds = new Set([...s1Tasks.keys(), ...s2Tasks.keys()]);
   343→
   344→    for (const taskId of allTaskIds) {
   345→      const t1 = s1Tasks.get(taskId);
   346→      const t2 = s2Tasks.get(taskId);
   347→
   348→      const status1 = t1?.status || 'N/A';
   349→      const status2 = t2?.status || 'N/A';
   350→
   351→      let delta = '';
   352→      let note = '';
   353→
   354→      if (status1 === 'pass' && status2 === 'fail') {
   355→        delta = chalk.red('REGRESSION');
   356→        note = 'Was passing, now failing';
   357→      } else if (status1 === 'fail' && status2 === 'pass') {
   358→        delta = chalk.green('IMPROVEMENT');
   359→        note = 'Was failing, now passing';
   360→      } else if (status1 === status2) {
   361→        delta = chalk.gray('unchanged');
   362→      } else {
   363→        delta = \`\${status1} -> \${status2}\`;
   364→      }
   365→
   366→      // Check metric changes
   367→      if (t1 && t2) {
   368→        const durationDelta = t2.durationMs - t1.durationMs;
   369→        if (Math.abs(durationDelta) > 1000) {
   370→          note += \` Duration: \${durationDelta > 0 ? '+' : ''}\${(durationDelta / 1000).toFixed(1)}s\`;
   371→        }
   372→      }
   373→
   374→      const statusColor1 = status1 === 'pass' ? chalk.green(status1) : status1 === 'fail' ? chalk.red(status1) : chalk.yellow(status1);
   375→      const statusColor2 = status2 === 'pass' ? chalk.green(status2) : status2 === 'fail' ? chalk.red(status2) : chalk.yellow(status2);
   376→
   377→      console.log(\`\${taskId.padEnd(25)} \${statusColor1.padEnd(19)} \${statusColor2.padEnd(19)} \${delta.padEnd(24)} \${chalk.gray(note)}\`);
   378→    }
   379→
   380→    // Cost comparison
   381→    if (summary1.totalCost.amount > 0 || summary2.totalCost.amount > 0) {
   382→      console.log(chalk.gray('\\n--- Cost ---'));
   383→      console.log(chalk.gray(\`Run A: $\${summary1.totalCost.amount.toFixed(4)}\`));
   384→      console.log(chalk.gray(\`Run B: $\${summary2.totalCost.amount.toFixed(4)}\`));
   385→      const costDelta = summary2.totalCost.amount - summary1.totalCost.amount;
   386→      console.log(chalk.gray(\`Delta: \${costDelta >= 0 ? '+' : ''}$\${costDelta.toFixed(4)}\`));
   387→    }
   388→
   389→    // Baseline comparison
   390→    if (summary2.baselineComparison) {
   391→      console.log(chalk.cyan('\\n--- Baseline Comparison ---'));
   392→      for (const [name, data] of Object.entries(summary2.baselineComparison)) {
   393→        const deltaStr = data.delta >= 0 ? chalk.green(\`+\${data.delta.toFixed(2)}\`) : chalk.red(data.delta.toFixed(2));
   394→        console.log(\`  \${name}: baseline=\${data.baseline.toFixed(2)} actual=\${data.actual.toFixed(2)} delta=\${deltaStr}\`);
   395→      }
   396→    }
   397→  }
   398→
   399→  async history(options: { spec?: string; limit?: number } = {}): Promise<void> {
   400→    const runs = this.resultsManager.listRuns();
   401→    let filtered = runs;
   402→
   403→    if (options.spec) {
   404→      filtered = filtered.filter(r => r.specName === options.spec);
   405→    }
   406→
   407→    const limit = options.limit || 20;
   408→    filtered = filtered.slice(0, limit);
   409→
   410→    if (filtered.length === 0) {
   411→      console.log(chalk.yellow('No eval runs found.'));
   412→      return;
   413→    }
   414→
   415→    console.log(chalk.cyan.bold('\\nEval History'));
   416→    console.log(chalk.gray(\`Showing \${filtered.length} of \${runs.length} runs\\n\`));
   417→
   418→    const header = \`\${'Run ID'.padEnd(20)} \${'Spec'.padEnd(20)} \${'Status'.padEnd(12)} \${'Tasks'.padEnd(8)} \${'Cost'.padEnd(10)} \${'Date'}\`;
   419→    console.log(chalk.white.bold(header));
   420→    console.log(chalk.gray('-'.repeat(90)));
   421→
   422→    for (const run of filtered) {
   423→      const statusColor = run.status === 'completed' ? chalk.green(run.status)
   424→        : run.status === 'failed' ? chalk.red(run.status)
   425→        : chalk.yellow(run.status);
   426→
   427→      const cost = run.totalCost ? \`$\${run.totalCost.amount.toFixed(4)}\` : '-';
   428→      const date = run.startedAt ? new Date(run.startedAt).toLocaleDateString() : '-';
   429→
   430→      console.log(\`\${run.runId.padEnd(20)} \${(run.specName || '-').padEnd(20)} \${statusColor.padEnd(21)} \${String(run.taskCount || 0).padEnd(8)} \${cost.padEnd(10)} \${date}\`);
   431→    }
   432→  }
   433→}
   434→`;
   435→}
