   437→export function generateTaskRegistry(): string {
   438→  return `import { spawn } from 'child_process';
   439→import * as path from 'path';
   440→import type { EvalContext } from './eval-executor.js';
   441→
   442→// ============================================================================
   443→// Types
   444→// ============================================================================
   445→
   446→export interface EvalTask {
   447→  id: string;
   448→  type: string;
   449→  command?: string;
   450→  timeout?: number;
   451→  criteria?: Record<string, any>;
   452→  prompt_template?: string;
   453→  context_files?: string[];
   454→  parse_output?: 'json' | 'text';
   455→  model?: string;
   456→  max_tokens?: number;
   457→  docker_registry?: string;
   458→  config?: Record<string, any>;
   459→}
   460→
   461→export interface TaskResult {
   462→  taskId: string;
   463→  type: string;
   464→  status: 'pass' | 'fail' | 'error' | 'skip';
   465→  startedAt: string;
   466→  completedAt: string;
   467→  durationMs: number;
   468→  command?: string;
   469→  exitCode?: number;
   470→  stdout?: string;
   471→  stderr?: string;
   472→  metrics: Record<string, number>;
   473→  criteria: Record<string, { expected: any; actual: any; passed: boolean }>;
   474→  error?: string;
   475→  judgment?: {
   476→    scores: Record<string, number>;
   477→    justifications: Record<string, string>;
   478→    averageScore: number;
   479→  };
   480→  predictions?: Array<{ instanceId: string; patch: string; resolved: boolean }>;
   481→  resolveRate?: number;
   482→  tokenUsage?: {
   483→    inputTokens: number;
   484→    outputTokens: number;
   485→    cacheReadTokens?: number;
   486→  };
   487→  estimatedCost?: {
   488→    amount: number;
   489→    currency: 'USD';
   490→    model: string;
   491→    breakdown?: { input: number; output: number; cacheRead?: number };
   492→  };
   493→}
   494→
   495→export interface TaskHandler {
   496→  type: string;
   497→  execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult>;
   498→}
   499→
   500→// ============================================================================
   501→// Task Registry
   502→// ============================================================================
   503→
   504→export class TaskRegistry {
   505→  private handlers: Map<string, TaskHandler> = new Map();
   506→
   507→  register(handler: TaskHandler): void {
   508→    this.handlers.set(handler.type, handler);
   509→  }
   510→
   511→  get(type: string): TaskHandler | undefined {
   512→    return this.handlers.get(type);
   513→  }
   514→
   515→  has(type: string): boolean {
   516→    return this.handlers.has(type);
   517→  }
   518→
   519→  listTypes(): string[] {
   520→    return Array.from(this.handlers.keys());
   521→  }
   522→}
   523→
   524→// ============================================================================
   525→// Command execution helper
   526→// ============================================================================
   527→
   528→interface CommandResult {
   529→  exitCode: number;
   530→  stdout: string;
   531→  stderr: string;
   532→}
   533→
   534→function runCommand(command: string, cwd: string, timeout: number = 120): Promise<CommandResult> {
   535→  return new Promise((resolve) => {
   536→    const child = spawn(command, [], {
   537→      shell: true,
   538→      cwd,
   539→      stdio: ['ignore', 'pipe', 'pipe'],
   540→      env: { ...process.env },
   541→    });
   542→
   543→    let stdout = '';
   544→    let stderr = '';
   545→
   546→    child.stdout.on('data', (data: Buffer) => {
   547→      stdout += data.toString();
   548→    });
   549→
   550→    child.stderr.on('data', (data: Buffer) => {
   551→      stderr += data.toString();
   552→    });
   553→
   554→    const timer = setTimeout(() => {
   555→      child.kill('SIGTERM');
   556→      resolve({ exitCode: 124, stdout, stderr: stderr + '\\nProcess timed out' });
   557→    }, timeout * 1000);
   558→
   559→    child.on('close', (code: number | null) => {
   560→      clearTimeout(timer);
   561→      resolve({ exitCode: code ?? 1, stdout, stderr });
   562→    });
   563→
