   622→export class TestHandler implements TaskHandler {
   623→  type = 'test';
   624→
   625→  async execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult> {
   626→    const start = Date.now();
   627→    const startedAt = new Date().toISOString();
   628→
   629→    if (!task.command) {
   630→      return {
   631→        taskId: task.id, type: task.type, status: 'error',
   632→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
   633→        metrics: {}, criteria: {}, error: 'No command specified for test task',
   634→      };
   635→    }
   636→
   637→    const result = await runCommand(task.command, ctx.targetDir, task.timeout || 300);
   638→    const completedAt = new Date().toISOString();
   639→    const durationMs = Date.now() - start;
   640→
   641→    const metrics: Record<string, number> = { exit_code: result.exitCode };
   642→    const criteria: Record<string, { expected: any; actual: any; passed: boolean }> = {};
   643→    let allPassed = true;
   644→
   645→    // Try to parse JSON test output
   646→    if (task.parse_output === 'json' || !task.parse_output) {
   647→      try {
   648→        // Look for JSON in stdout (handle test runners that add extra output)
   649→        const jsonMatch = result.stdout.match(/\\{[\\s\\S]*\\}/);
   650→        if (jsonMatch) {
   651→          const parsed = JSON.parse(jsonMatch[0]);
   652→          if (parsed.numPassedTests !== undefined && parsed.numTotalTests !== undefined) {
   653→            const passRate = parsed.numTotalTests > 0 ? parsed.numPassedTests / parsed.numTotalTests : 0;
   654→            metrics['pass_rate'] = passRate;
   655→            metrics['passed'] = parsed.numPassedTests;
   656→            metrics['failed'] = parsed.numFailedTests || 0;
   657→            metrics['total'] = parsed.numTotalTests;
   658→
   659→            if (parsed.coverageMap?.total?.lines?.pct !== undefined) {
   660→              metrics['coverage'] = parsed.coverageMap.total.lines.pct;
   661→            }
   662→          }
   663→        }
   664→      } catch {}
   665→    }
   666→
   667→    // Evaluate criteria
   668→    if (task.criteria?.min_pass_rate !== undefined && metrics.pass_rate !== undefined) {
   669→      const passed = metrics.pass_rate >= task.criteria.min_pass_rate;
   670→      criteria['min_pass_rate'] = { expected: task.criteria.min_pass_rate, actual: metrics.pass_rate, passed };
   671→      if (!passed) allPassed = false;
   672→    }
   673→
   674→    if (task.criteria?.exit_code !== undefined) {
   675→      const passed = result.exitCode === task.criteria.exit_code;
   676→      criteria['exit_code'] = { expected: task.criteria.exit_code, actual: result.exitCode, passed };
   677→      if (!passed) allPassed = false;
   678→    }
   679→
   680→    if (task.criteria?.min_coverage !== undefined && metrics.coverage !== undefined) {
   681→      const passed = metrics.coverage >= task.criteria.min_coverage;
   682→      criteria['min_coverage'] = { expected: task.criteria.min_coverage, actual: metrics.coverage, passed };
   683→      if (!passed) allPassed = false;
   684→    }
   685→
   686→    // If no criteria matched, default to exit code check
   687→    if (Object.keys(criteria).length === 0) {
   688→      const passed = result.exitCode === 0;
   689→      criteria['exit_code'] = { expected: 0, actual: result.exitCode, passed };
   690→      if (!passed) allPassed = false;
   691→    }
   692→
   693→    return {
   694→      taskId: task.id, type: task.type,
   695→      status: allPassed ? 'pass' : 'fail',
   696→      startedAt, completedAt, durationMs,
   697→      command: task.command,
   698→      exitCode: result.exitCode,
   699→      stdout: result.stdout.slice(-10000),
   700→      stderr: result.stderr.slice(-5000),
   701→      metrics, criteria,
   702→    };
   703→  }
   704→}
