  1013→export function generateSpecParser(): string {
  1014→  return `import * as fs from 'fs';
  1015→import * as yaml from 'js-yaml';
  1016→
  1017→export interface EvalSpec {
  1018→  name: string;
  1019→  version: string;
  1020→  target: {
  1021→    repo?: string;
  1022→    ref?: string;
  1023→    dataset?: string;
  1024→    subset?: number;
  1025→  };
  1026→  tasks: EvalTask[];
  1027→  baselines?: Record<string, number>;
  1028→}
  1029→
  1030→export interface EvalTask {
  1031→  id: string;
  1032→  type: string;
  1033→  command?: string;
  1034→  timeout?: number;
  1035→  criteria?: Record<string, any>;
  1036→  prompt_template?: string;
  1037→  context_files?: string[];
  1038→  parse_output?: 'json' | 'text';
  1039→  model?: string;
  1040→  max_tokens?: number;
  1041→  docker_registry?: string;
  1042→  config?: Record<string, any>;
  1043→}
  1044→
  1045→export class SpecParser {
  1046→  parse(filePath: string): EvalSpec {
  1047→    if (!fs.existsSync(filePath)) {
  1048→      throw new Error(\`Spec file not found: \${filePath}\`);
  1049→    }
  1050→
  1051→    const content = fs.readFileSync(filePath, 'utf-8');
  1052→    let data: any;
  1053→
  1054→    if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
  1055→      data = yaml.load(content);
  1056→    } else if (filePath.endsWith('.json')) {
  1057→      data = JSON.parse(content);
  1058→    } else {
  1059→      throw new Error(\`Unsupported spec format. Use .yaml, .yml, or .json\`);
  1060→    }
  1061→
  1062→    return this.validate(data);
  1063→  }
  1064→
  1065→  private validate(data: any): EvalSpec {
  1066→    if (!data || typeof data !== 'object') {
  1067→      throw new Error('Spec must be a YAML/JSON object');
  1068→    }
  1069→
  1070→    if (!data.name || typeof data.name !== 'string') {
  1071→      throw new Error('Spec must have a "name" field (string)');
  1072→    }
  1073→
  1074→    if (!data.version || typeof data.version !== 'string') {
  1075→      throw new Error('Spec must have a "version" field (string)');
  1076→    }
  1077→
  1078→    if (!data.target || typeof data.target !== 'object') {
  1079→      throw new Error('Spec must have a "target" field (object with repo or dataset)');
  1080→    }
  1081→
  1082→    if (!data.tasks || !Array.isArray(data.tasks) || data.tasks.length === 0) {
  1083→      throw new Error('Spec must have a "tasks" array with at least one task');
  1084→    }
  1085→
  1086→    for (let i = 0; i < data.tasks.length; i++) {
  1087→      const task = data.tasks[i];
  1088→      if (!task.id || typeof task.id !== 'string') {
  1089→        throw new Error(\`Task \${i} must have an "id" field (string)\`);
  1090→      }
  1091→      if (!task.type || typeof task.type !== 'string') {
  1092→        throw new Error(\`Task "\${task.id}" must have a "type" field (string)\`);
  1093→      }
  1094→    }
  1095→
  1096→    return data as EvalSpec;
  1097→  }
  1098→}
  1099→`;
  1100→}
  1101→
  1102→export function generateReportGenerator(): string {
  1103→  return `export class ReportGenerator {
  1104→  generateJSON(manifest: any, taskResults: any[], baselines?: Record<string, number>): any {
  1105→    const passCount = taskResults.filter(t => t.status === 'pass').length;
  1106→    const failCount = taskResults.filter(t => t.status === 'fail').length;
  1107→    const errorCount = taskResults.filter(t => t.status === 'error').length;
  1108→    const totalDurationMs = taskResults.reduce((sum, t) => sum + (t.durationMs || 0), 0);
  1109→
  1110→    // Aggregate metrics across tasks
  1111→    const aggregateMetrics: Record<string, number> = {};
  1112→    for (const result of taskResults) {
  1113→      for (const [key, value] of Object.entries(result.metrics || {})) {
  1114→        if (typeof value === 'number') {
  1115→          aggregateMetrics[\`\${result.taskId}.\${key}\`] = value;
  1116→        }
  1117→      }
  1118→    }
  1119→
  1120→    // Calculate total cost
  1121→    let totalCostAmount = 0;
  1122→    const costBreakdown: Record<string, number> = {};
  1123→    for (const result of taskResults) {
  1124→      if (result.estimatedCost?.amount) {
  1125→        totalCostAmount += result.estimatedCost.amount;
  1126→        costBreakdown[result.taskId] = result.estimatedCost.amount;
  1127→      }
  1128→    }
  1129→
  1130→    // Baseline comparison
  1131→    let baselineComparison: Record<string, { baseline: number; actual: number; delta: number }> | undefined;
  1132→    if (baselines) {
  1133→      baselineComparison = {};
  1134→      // Use resolve rate if available, otherwise pass rate
  1135→      const resolveResults = taskResults.filter(t => t.resolveRate !== undefined);
  1136→      const actual = resolveResults.length > 0
  1137→        ? resolveResults[0].resolveRate
  1138→        : passCount / Math.max(taskResults.length, 1);
  1139→
  1140→      for (const [name, baseline] of Object.entries(baselines)) {
  1141→        baselineComparison[name] = {
  1142→          baseline,
  1143→          actual: actual || 0,
  1144→          delta: (actual || 0) - baseline,
  1145→        };
  1146→      }
  1147→    }
  1148→
  1149→    const overallStatus = failCount > 0 || errorCount > 0
  1150→      ? (passCount > 0 ? 'mixed' : 'fail')
  1151→      : 'pass';
  1152→
  1153→    return {
  1154→      runId: manifest.runId,
  1155→      specName: manifest.specName,
  1156→      completedAt: manifest.completedAt || new Date().toISOString(),
  1157→      overallStatus,
  1158→      tasks: taskResults.map(t => ({
  1159→        taskId: t.taskId,
  1160→        type: t.type,
  1161→        status: t.status,
  1162→        durationMs: t.durationMs,
  1163→        metrics: t.metrics || {},
  1164→        cost: t.estimatedCost?.amount,
  1165→      })),
  1166→      aggregateMetrics,
  1167→      passCount,
  1168→      failCount,
  1169→      errorCount,
  1170→      totalDurationMs,
  1171→      totalCost: { amount: totalCostAmount, currency: 'USD', breakdown: costBreakdown },
  1172→      baselineComparison,
  1173→    };
  1174→  }
  1175→
  1176→  generateMarkdown(manifest: any, taskResults: any[], baselines?: Record<string, number>): string {
  1177→    const summary = this.generateJSON(manifest, taskResults, baselines);
  1178→    const lines: string[] = [];
  1179→
  1180→    lines.push(\`# Eval Report: \${summary.specName}\`);
  1181→    lines.push(\`\`);
  1182→    lines.push(\`**Run ID:** \${summary.runId}\`);
  1183→    lines.push(\`**Date:** \${summary.completedAt}\`);
  1184→    lines.push(\`**Overall Status:** \${summary.overallStatus.toUpperCase()}\`);
  1185→    lines.push(\`\`);
  1186→
  1187→    // Summary stats
  1188→    lines.push(\`## Summary\`);
  1189→    lines.push(\`\`);
  1190→    lines.push(\`| Metric | Value |\`);
  1191→    lines.push(\`|--------|-------|\`);
  1192→    lines.push(\`| Tasks Run | \${taskResults.length} |\`);
  1193→    lines.push(\`| Passed | \${summary.passCount} |\`);
  1194→    lines.push(\`| Failed | \${summary.failCount} |\`);
  1195→    lines.push(\`| Errors | \${summary.errorCount} |\`);
  1196→    lines.push(\`| Total Duration | \${(summary.totalDurationMs / 1000).toFixed(1)}s |\`);
  1197→    if (summary.totalCost.amount > 0) {
  1198→      lines.push(\`| Total Cost | $\${summary.totalCost.amount.toFixed(4)} |\`);
  1199→    }
  1200→    lines.push(\`\`);
  1201→
  1202→    // Task details
  1203→    lines.push(\`## Tasks\`);
  1204→    lines.push(\`\`);
  1205→    lines.push(\`| Task | Type | Status | Duration | Cost |\`);
  1206→    lines.push(\`|------|------|--------|----------|------|\`);
  1207→
  1208→    for (const task of summary.tasks) {
  1209→      const statusIcon = task.status === 'pass' ? '\\u2705' : task.status === 'fail' ? '\\u274c' : task.status === 'skip' ? '\\u23ed' : '\\u26a0\\ufe0f';
  1210→      const cost = task.cost ? \`$\${task.cost.toFixed(4)}\` : '-';
  1211→      lines.push(\`| \${task.taskId} | \${task.type} | \${statusIcon} \${task.status} | \${(task.durationMs / 1000).toFixed(1)}s | \${cost} |\`);
  1212→    }
  1213→    lines.push(\`\`);
  1214→
  1215→    // Criteria details
  1216→    lines.push(\`## Criteria Results\`);
  1217→    lines.push(\`\`);
  1218→    for (const result of taskResults) {
  1219→      if (Object.keys(result.criteria || {}).length > 0) {
  1220→        lines.push(\`### \${result.taskId}\`);
  1221→        lines.push(\`\`);
  1222→        for (const [name, crit] of Object.entries(result.criteria as Record<string, any>)) {
  1223→          const icon = crit.passed ? '\\u2705' : '\\u274c';
  1224→          lines.push(\`- \${icon} **\${name}**: expected=\${crit.expected}, actual=\${crit.actual}\`);
  1225→        }
  1226→        lines.push(\`\`);
  1227→      }
  1228→    }
  1229→
  1230→    // Baseline comparison
  1231→    if (summary.baselineComparison) {
  1232→      lines.push(\`## Baseline Comparison\`);
  1233→      lines.push(\`\`);
  1234→      lines.push(\`| Baseline | Score | Actual | Delta |\`);
  1235→      lines.push(\`|----------|-------|--------|-------|\`);
  1236→      for (const [name, data] of Object.entries(summary.baselineComparison)) {
  1237→        const deltaStr = data.delta >= 0 ? \`+\${data.delta.toFixed(3)}\` : data.delta.toFixed(3);
  1238→        lines.push(\`| \${name} | \${data.baseline.toFixed(3)} | \${data.actual.toFixed(3)} | \${deltaStr} |\`);
  1239→      }
  1240→      lines.push(\`\`);
  1241→    }
  1242→
  1243→    // Cost breakdown
  1244→    if (summary.totalCost.amount > 0) {
  1245→      lines.push(\`## Cost Breakdown\`);
  1246→      lines.push(\`\`);
  1247→      lines.push(\`| Task | Cost |\`);
  1248→      lines.push(\`|------|------|\`);
  1249→      for (const [taskId, cost] of Object.entries(summary.totalCost.breakdown as Record<string, number>)) {
  1250→        lines.push(\`| \${taskId} | $\${cost.toFixed(4)} |\`);
  1251→      }
  1252→      lines.push(\`| **Total** | **$\${summary.totalCost.amount.toFixed(4)}** |\`);
  1253→      lines.push(\`\`);
  1254→    }
  1255→
  1256→    return lines.join('\\n');
  1257→  }
  1258→}
  1259→`;
  1260→}
