  1452→export function generateAgentEvalHandler(): string {
  1453→  return `import { spawn } from 'child_process';
  1454→import * as fs from 'fs';
  1455→import * as path from 'path';
  1456→import type { EvalContext } from '../eval-executor.js';
  1457→import type { EvalTask, TaskResult, TaskHandler } from '../task-registry.js';
  1458→
  1459→export class AgentEvalHandler implements TaskHandler {
  1460→  type = 'agent-eval';
  1461→
  1462→  async execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult> {
  1463→    const start = Date.now();
  1464→    const startedAt = new Date().toISOString();
  1465→
  1466→    // Check for Python and Docker availability
  1467→    const pythonAvailable = await this.checkCommand('python3 --version');
  1468→    const dockerAvailable = await this.checkCommand('docker info');
  1469→
  1470→    if (!pythonAvailable || !dockerAvailable) {
  1471→      return {
  1472→        taskId: task.id, type: task.type, status: 'skip',
  1473→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1474→        metrics: {}, criteria: {},
  1475→        error: \`\${!pythonAvailable ? 'Python' : 'Docker'} not available. Agent-eval requires both Python and Docker.\`,
  1476→      };
  1477→    }
  1478→
  1479→    // Check for harness directory
  1480→    const harnessDir = path.join(ctx.workingDir, 'harness');
  1481→    if (!fs.existsSync(path.join(harnessDir, 'run_task.py'))) {
  1482→      return {
  1483→        taskId: task.id, type: task.type, status: 'error',
  1484→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1485→        metrics: {}, criteria: {},
  1486→        error: 'harness/run_task.py not found. Ensure the Python harness is set up.',
  1487→      };
  1488→    }
  1489→
  1490→    const model = task.model || 'claude-sonnet-4-20250514';
  1491→    const maxTokens = task.max_tokens || 200000;
  1492→    const timeout = task.timeout || 600;
  1493→
  1494→    try {
  1495→      // Run the Python harness
  1496→      const result = await this.runPythonHarness({
  1497→        harnessDir,
  1498→        model,
  1499→        maxTokens,
  1500→        timeout,
  1501→        dataset: task.config?.dataset || 'princeton-nlp/SWE-bench_Verified',
  1502→        subset: task.config?.subset || 20,
  1503→        dockerRegistry: task.docker_registry || 'ghcr.io/epoch-research',
  1504→        apiKey: ctx.apiKey,
  1505→        outputDir: path.join(ctx.workingDir, '.eval-runs', ctx.runId, 'predictions'),
  1506→      });
  1507→
  1508→      const completedAt = new Date().toISOString();
  1509→      const durationMs = Date.now() - start;
  1510→
  1511→      // Parse predictions output
  1512→      let predictions: Array<{ instanceId: string; patch: string; resolved: boolean }> = [];
  1513→      const predictionsFile = path.join(ctx.workingDir, '.eval-runs', ctx.runId, 'predictions', 'predictions.jsonl');
  1514→      if (fs.existsSync(predictionsFile)) {
  1515→        const lines = fs.readFileSync(predictionsFile, 'utf-8').trim().split('\\n');
  1516→        for (const line of lines) {
  1517→          try {
  1518→            const p = JSON.parse(line);
  1519→            predictions.push({
  1520→              instanceId: p.instance_id || p.instanceId,
  1521→              patch: p.model_patch || p.patch || '',
  1522→              resolved: p.resolved || false,
  1523→            });
  1524→          } catch {}
  1525→        }
  1526→      }
  1527→
  1528→      const resolvedCount = predictions.filter(p => p.resolved).length;
  1529→      const resolveRate = predictions.length > 0 ? resolvedCount / predictions.length : 0;
  1530→
  1531→      const metrics: Record<string, number> = {
  1532→        resolve_rate: resolveRate,
  1533→        resolved: resolvedCount,
  1534→        total: predictions.length,
  1535→        exit_code: result.exitCode,
  1536→      };
  1537→
  1538→      if (result.tokenUsage) {
  1539→        metrics['input_tokens'] = result.tokenUsage.inputTokens;
  1540→        metrics['output_tokens'] = result.tokenUsage.outputTokens;
  1541→      }
  1542→
  1543→      // Evaluate criteria
  1544→      const criteria: Record<string, { expected: any; actual: any; passed: boolean }> = {};
  1545→      let allPassed = true;
  1546→
  1547→      if (task.criteria?.min_resolve_rate !== undefined) {
  1548→        const passed = resolveRate >= task.criteria.min_resolve_rate;
  1549→        criteria['min_resolve_rate'] = { expected: task.criteria.min_resolve_rate, actual: resolveRate, passed };
  1550→        if (!passed) allPassed = false;
  1551→      }
  1552→
  1553→      return {
  1554→        taskId: task.id, type: task.type,
  1555→        status: result.exitCode !== 0 ? 'error' : (allPassed ? 'pass' : 'fail'),
  1556→        startedAt, completedAt, durationMs,
  1557→        metrics, criteria,
  1558→        predictions,
  1559→        resolveRate,
  1560→        tokenUsage: result.tokenUsage,
  1561→        estimatedCost: result.estimatedCost,
  1562→        stdout: result.stdout.slice(-10000),
  1563→        stderr: result.stderr.slice(-5000),
  1564→        error: result.exitCode !== 0 ? \`Python harness exited with code \${result.exitCode}\` : undefined,
  1565→      };
  1566→    } catch (error) {
  1567→      return {
  1568→        taskId: task.id, type: task.type, status: 'error',
  1569→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1570→        metrics: {}, criteria: {},
  1571→        error: \`Agent eval failed: \${error instanceof Error ? error.message : String(error)}\`,
  1572→      };
  1573→    }
  1574→  }
  1575→
  1576→  private checkCommand(cmd: string): Promise<boolean> {
  1577→    return new Promise((resolve) => {
  1578→      const child = spawn(cmd, [], { shell: true, stdio: 'pipe' });
  1579→      child.on('close', (code) => resolve(code === 0));
  1580→      child.on('error', () => resolve(false));
  1581→    });
  1582→  }
  1583→
  1584→  private runPythonHarness(options: {
  1585→    harnessDir: string;
  1586→    model: string;
  1587→    maxTokens: number;
  1588→    timeout: number;
  1589→    dataset: string;
  1590→    subset: number;
  1591→    dockerRegistry: string;
  1592→    apiKey?: string;
  1593→    outputDir: string;
  1594→  }): Promise<{ exitCode: number; stdout: string; stderr: string; tokenUsage?: any; estimatedCost?: any }> {
  1595→    return new Promise((resolve) => {
  1596→      const args = [
  1597→        'run_task.py',
  1598→        '--model', options.model,
  1599→        '--max-tokens', String(options.maxTokens),
  1600→        '--dataset', options.dataset,
  1601→        '--subset', String(options.subset),
  1602→        '--docker-registry', options.dockerRegistry,
  1603→        '--output-dir', options.outputDir,
  1604→      ];
  1605→
  1606→      const env = { ...process.env };
  1607→      if (options.apiKey) {
  1608→        env['ANTHROPIC_API_KEY'] = options.apiKey;
  1609→      }
  1610→
  1611→      const child = spawn('python3', args, {
  1612→        cwd: options.harnessDir,
  1613→        stdio: ['ignore', 'pipe', 'pipe'],
  1614→        env,
  1615→      });
  1616→
  1617→      let stdout = '';
  1618→      let stderr = '';
  1619→
