   437→export function generateTaskRegistry(): string {
   438→  return `import { spawn } from 'child_process';
   439→import * as path from 'path';
   440→import type { EvalContext } from './eval-executor.js';
   441→
   442→// ============================================================================
   443→// Types
   444→// ============================================================================
   445→
   446→export interface EvalTask {
