   465→  startedAt: string;
   466→  completedAt: string;
   467→  durationMs: number;
   468→  command?: string;
   469→  exitCode?: number;
   470→  stdout?: string;
   471→  stderr?: string;
   472→  metrics: Record<string, number>;
   473→  criteria: Record<string, { expected: any; actual: any; passed: boolean }>;
   474→  error?: string;
   475→  judgment?: {
   476→    scores: Record<string, number>;
