   493→}
   494→
   495→export interface TaskHandler {
   496→  type: string;
   497→  execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult>;
   498→}
   499→
   500→// ============================================================================
   501→// Task Registry
   502→// ============================================================================
   503→
   504→export class TaskRegistry {
   505→  private handlers: Map<string, TaskHandler> = new Map();
   506→
   507→  register(handler: TaskHandler): void {
   508→    this.handlers.set(handler.type, handler);
   509→  }
   510→
   511→  get(type: string): TaskHandler | undefined {
   512→    return this.handlers.get(type);
   513→  }
   514→
   515→  has(type: string): boolean {
   516→    return this.handlers.has(type);
