   523→
   524→// ============================================================================
   525→// Command execution helper
   526→// ============================================================================
   527→
   528→interface CommandResult {
   529→  exitCode: number;
   530→  stdout: string;
   531→  stderr: string;
   532→}
   533→
   534→function runCommand(command: string, cwd: string, timeout: number = 120): Promise<CommandResult> {
   535→  return new Promise((resolve) => {
   536→    const child = spawn(command, [], {
   537→      shell: true,
   538→      cwd,
   539→      stdio: ['ignore', 'pipe', 'pipe'],
   540→      env: { ...process.env },
   541→    });
   542→
   543→    let stdout = '';
   544→    let stderr = '';
   545→
   546→    child.stdout.on('data', (data: Buffer) => {
   547→      stdout += data.toString();
   548→    });
   549→
   550→    child.stderr.on('data', (data: Buffer) => {
   551→      stderr += data.toString();
   552→    });
   553→
   554→    const timer = setTimeout(() => {
   555→      child.kill('SIGTERM');
   556→      resolve({ exitCode: 124, stdout, stderr: stderr + '\\nProcess timed out' });
   557→    }, timeout * 1000);
   558→
   559→    child.on('close', (code: number | null) => {
   560→      clearTimeout(timer);
   561→      resolve({ exitCode: code ?? 1, stdout, stderr });
   562→    });
   563→
   564→    child.on('error', (err: Error) => {
   565→      clearTimeout(timer);
   566→      resolve({ exitCode: 1, stdout, stderr: err.message });
   567→    });
   568→  });
   569→}
