   575→export class BuildHandler implements TaskHandler {
   576→  type = 'build';
   577→
   578→  async execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult> {
   579→    const start = Date.now();
   580→    const startedAt = new Date().toISOString();
   581→
   582→    if (!task.command) {
   583→      return {
   584→        taskId: task.id, type: task.type, status: 'error',
   585→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
   586→        metrics: {}, criteria: {}, error: 'No command specified for build task',
   587→      };
   588→    }
   589→
   590→    const result = await runCommand(task.command, ctx.targetDir, task.timeout || 120);
   591→    const completedAt = new Date().toISOString();
   592→    const durationMs = Date.now() - start;
   593→
   594→    const criteria: Record<string, { expected: any; actual: any; passed: boolean }> = {};
   595→    let allPassed = true;
   596→
   597→    if (task.criteria?.exit_code !== undefined) {
   598→      const passed = result.exitCode === task.criteria.exit_code;
   599→      criteria['exit_code'] = { expected: task.criteria.exit_code, actual: result.exitCode, passed };
   600→      if (!passed) allPassed = false;
   601→    } else {
   602→      // Default: expect exit code 0
   603→      const passed = result.exitCode === 0;
   604→      criteria['exit_code'] = { expected: 0, actual: result.exitCode, passed };
   605→      if (!passed) allPassed = false;
   606→    }
   607→
   608→    return {
   609→      taskId: task.id, type: task.type,
   610→      status: allPassed ? 'pass' : 'fail',
   611→      startedAt, completedAt, durationMs,
   612→      command: task.command,
   613→      exitCode: result.exitCode,
   614→      stdout: result.stdout.slice(-10000),
   615→      stderr: result.stderr.slice(-5000),
   616→      metrics: { exit_code: result.exitCode },
   617→      criteria,
   618→    };
   619→  }
   620→}
