   706→export class LintHandler implements TaskHandler {
   707→  type = 'lint';
   708→
   709→  async execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult> {
   710→    const start = Date.now();
   711→    const startedAt = new Date().toISOString();
   712→
   713→    if (!task.command) {
   714→      return {
   715→        taskId: task.id, type: task.type, status: 'error',
