   721→    const result = await runCommand(task.command, ctx.targetDir, task.timeout || 120);
   722→    const completedAt = new Date().toISOString();
   723→    const durationMs = Date.now() - start;
   724→
   725→    const metrics: Record<string, number> = { exit_code: result.exitCode };
   726→    const criteria: Record<string, { expected: any; actual: any; passed: boolean }> = {};
   727→    let allPassed = true;
   728→
   729→    // Try to parse ESLint JSON output
   730→    try {
   731→      const parsed = JSON.parse(result.stdout);
   732→      if (Array.isArray(parsed)) {
   733→        let errors = 0;
   734→        let warnings = 0;
   735→        for (const file of parsed) {
   736→          errors += file.errorCount || 0;
   737→          warnings += file.warningCount || 0;
   738→        }
   739→        metrics['errors'] = errors;
   740→        metrics['warnings'] = warnings;
   741→        metrics['files_checked'] = parsed.length;
   742→      }
   743→    } catch {}
   744→
   745→    // Evaluate criteria
   746→    if (task.criteria?.max_errors !== undefined && metrics.errors !== undefined) {
   747→      const passed = metrics.errors <= task.criteria.max_errors;
   748→      criteria['max_errors'] = { expected: task.criteria.max_errors, actual: metrics.errors, passed };
   749→      if (!passed) allPassed = false;
   750→    }
   751→
   752→    if (task.criteria?.max_warnings !== undefined && metrics.warnings !== undefined) {
   753→      const passed = metrics.warnings <= task.criteria.max_warnings;
   754→      criteria['max_warnings'] = { expected: task.criteria.max_warnings, actual: metrics.warnings, passed };
   755→      if (!passed) allPassed = false;
   756→    }
   757→
   758→    if (Object.keys(criteria).length === 0) {
   759→      const passed = result.exitCode === 0;
   760→      criteria['exit_code'] = { expected: 0, actual: result.exitCode, passed };
   761→      if (!passed) allPassed = false;
   762→    }
   763→
   764→    return {
   765→      taskId: task.id, type: task.type,
   766→      status: allPassed ? 'pass' : 'fail',
   767→      startedAt, completedAt, durationMs,
   768→      command: task.command,
   769→      exitCode: result.exitCode,
   770→      stdout: result.stdout.slice(-10000),
   771→      stderr: result.stderr.slice(-5000),
   772→      metrics, criteria,
   773→    };
   774→  }
   775→}
