   948→
   949→  createRun(): string {
   950→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
   951→    const id = \`run-\${timestamp}-\${Math.random().toString(36).slice(2, 6)}\`;
   952→    const runDir = path.join(this.baseDir, id);
   953→
   954→    fs.mkdirSync(path.join(runDir, 'tasks'), { recursive: true });
   955→    fs.mkdirSync(path.join(runDir, 'predictions'), { recursive: true });
   956→
