   997→
   998→  listRuns(): any[] {
   999→    if (!fs.existsSync(this.baseDir)) return [];
  1000→
  1001→    return fs.readdirSync(this.baseDir)
  1002→      .filter(d => d.startsWith('run-') && fs.statSync(path.join(this.baseDir, d)).isDirectory())
  1003→      .sort((a, b) => b.localeCompare(a)) // Newest first
  1004→      .map(runId => {
  1005→        const manifest = this.readManifest(runId);
  1006→        return manifest ? { runId, ...manifest } : { runId, status: 'unknown' };
  1007→      });
  1008→  }
  1009→}
  1010→`;
  1011→}
