  1013→export function generateSpecParser(): string {
  1014→  return `import * as fs from 'fs';
  1015→import * as yaml from 'js-yaml';
  1016→
  1017→export interface EvalSpec {
  1018→  name: string;
  1019→  version: string;
  1020→  target: {
  1021→    repo?: string;
  1022→    ref?: string;
  1023→    dataset?: string;
  1024→    subset?: number;
  1025→  };
  1026→  tasks: EvalTask[];
  1027→  baselines?: Record<string, number>;
  1028→}
  1029→
  1030→export interface EvalTask {
  1031→  id: string;
  1032→  type: string;
  1033→  command?: string;
  1034→  timeout?: number;
  1035→  criteria?: Record<string, any>;
  1036→  prompt_template?: string;
  1037→  context_files?: string[];
  1038→  parse_output?: 'json' | 'text';
  1039→  model?: string;
  1040→  max_tokens?: number;
  1041→  docker_registry?: string;
  1042→  config?: Record<string, any>;
  1043→}
  1044→
  1045→export class SpecParser {
  1046→  parse(filePath: string): EvalSpec {
  1047→    if (!fs.existsSync(filePath)) {
  1048→      throw new Error(\`Spec file not found: \${filePath}\`);
  1049→    }
  1050→
  1051→    const content = fs.readFileSync(filePath, 'utf-8');
  1052→    let data: any;
  1053→
  1054→    if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
  1055→      data = yaml.load(content);
  1056→    } else if (filePath.endsWith('.json')) {
  1057→      data = JSON.parse(content);
  1058→    } else {
  1059→      throw new Error(\`Unsupported spec format. Use .yaml, .yml, or .json\`);
  1060→    }
  1061→
  1062→    return this.validate(data);
  1063→  }
  1064→
  1065→  private validate(data: any): EvalSpec {
  1066→    if (!data || typeof data !== 'object') {
  1067→      throw new Error('Spec must be a YAML/JSON object');
  1068→    }
  1069→
  1070→    if (!data.name || typeof data.name !== 'string') {
  1071→      throw new Error('Spec must have a "name" field (string)');
  1072→    }
  1073→
  1074→    if (!data.version || typeof data.version !== 'string') {
  1075→      throw new Error('Spec must have a "version" field (string)');
  1076→    }
  1077→
  1078→    if (!data.target || typeof data.target !== 'object') {
  1079→      throw new Error('Spec must have a "target" field (object with repo or dataset)');
  1080→    }
  1081→
  1082→    if (!data.tasks || !Array.isArray(data.tasks) || data.tasks.length === 0) {
  1083→      throw new Error('Spec must have a "tasks" array with at least one task');
  1084→    }
  1085→
  1086→    for (let i = 0; i < data.tasks.length; i++) {
  1087→      const task = data.tasks[i];
  1088→      if (!task.id || typeof task.id !== 'string') {
  1089→        throw new Error(\`Task \${i} must have an "id" field (string)\`);
  1090→      }
  1091→      if (!task.type || typeof task.type !== 'string') {
  1092→        throw new Error(\`Task "\${task.id}" must have a "type" field (string)\`);
  1093→      }
  1094→    }
  1095→
  1096→    return data as EvalSpec;
  1097→  }
  1098→}
  1099→`;
  1100→}
