  1207→
  1208→    for (const task of summary.tasks) {
  1209→      const statusIcon = task.status === 'pass' ? '\\u2705' : task.status === 'fail' ? '\\u274c' : task.status === 'skip' ? '\\u23ed' : '\\u26a0\\ufe0f';
  1210→      const cost = task.cost ? \`$\${task.cost.toFixed(4)}\` : '-';
  1211→      lines.push(\`| \${task.taskId} | \${task.type} | \${statusIcon} \${task.status} | \${(task.durationMs / 1000).toFixed(1)}s | \${cost} |\`);
  1212→    }
  1213→    lines.push(\`\`);
  1214→
  1215→    // Criteria details
