  1233→      lines.push(\`\`);
  1234→      lines.push(\`| Baseline | Score | Actual | Delta |\`);
  1235→      lines.push(\`|----------|-------|--------|-------|\`);
  1236→      for (const [name, data] of Object.entries(summary.baselineComparison)) {
  1237→        const deltaStr = data.delta >= 0 ? \`+\${data.delta.toFixed(3)}\` : data.delta.toFixed(3);
  1238→        lines.push(\`| \${name} | \${data.baseline.toFixed(3)} | \${data.actual.toFixed(3)} | \${deltaStr} |\`);
  1239→      }
  1240→      lines.push(\`\`);
  1241→    }
  1242→
  1243→    // Cost breakdown
  1244→    if (summary.totalCost.amount > 0) {
  1245→      lines.push(\`## Cost Breakdown\`);
  1246→      lines.push(\`\`);
  1247→      lines.push(\`| Task | Cost |\`);
  1248→      lines.push(\`|------|------|\`);
  1249→      for (const [taskId, cost] of Object.entries(summary.totalCost.breakdown as Record<string, number>)) {
  1250→        lines.push(\`| \${taskId} | $\${cost.toFixed(4)} |\`);
  1251→      }
  1252→      lines.push(\`| **Total** | **$\${summary.totalCost.amount.toFixed(4)}** |\`);
  1253→      lines.push(\`\`);
  1254→    }
  1255→
  1256→    return lines.join('\\n');
  1257→  }
  1258→}
  1259→`;
  1260→}
