  1262→export function generateLLMJudgeHandler(): string {
  1263→  return `import * as fs from 'fs';
  1264→import * as path from 'path';
  1265→import { glob } from 'glob';
  1266→import Anthropic from '@anthropic-ai/sdk';
  1267→import type { EvalContext } from '../eval-executor.js';
  1268→import type { EvalTask, TaskResult, TaskHandler } from '../task-registry.js';
  1269→
  1270→// Model pricing per million tokens (USD)
  1271→const MODEL_PRICING: Record<string, { input: number; output: number; cacheRead?: number }> = {
  1272→  'claude-sonnet-4-20250514':  { input: 3.0,  output: 15.0, cacheRead: 0.30 },
  1273→  'claude-opus-4-20250514':    { input: 15.0, output: 75.0, cacheRead: 1.50 },
  1274→  'claude-haiku-3-5-20241022': { input: 0.80, output: 4.0,  cacheRead: 0.08 },
  1275→};
  1276→
  1277→function calculateCost(model: string, usage: { inputTokens: number; outputTokens: number; cacheReadTokens?: number }) {
  1278→  const pricing = MODEL_PRICING[model] || MODEL_PRICING['claude-sonnet-4-20250514'];
  1279→  const inputCost = (usage.inputTokens * pricing.input) / 1_000_000;
  1280→  const outputCost = (usage.outputTokens * pricing.output) / 1_000_000;
  1281→  const cacheReadCost = usage.cacheReadTokens && pricing.cacheRead
  1282→    ? (usage.cacheReadTokens * pricing.cacheRead) / 1_000_000
  1283→    : 0;
  1284→
  1285→  return {
  1286→    amount: inputCost + outputCost + cacheReadCost,
  1287→    currency: 'USD' as const,
  1288→    model,
  1289→    breakdown: { input: inputCost, output: outputCost, cacheRead: cacheReadCost },
  1290→  };
  1291→}
  1292→
  1293→export class LLMJudgeHandler implements TaskHandler {
  1294→  type = 'llm-judge';
  1295→
  1296→  async execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult> {
  1297→    const start = Date.now();
  1298→    const startedAt = new Date().toISOString();
  1299→
  1300→    const model = task.model || 'claude-sonnet-4-20250514';
  1301→
  1302→    if (!task.prompt_template) {
  1303→      return {
  1304→        taskId: task.id, type: task.type, status: 'error',
  1305→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1306→        metrics: {}, criteria: {}, error: 'No prompt_template specified for llm-judge task',
  1307→      };
  1308→    }
  1309→
  1310→    // Gather context files
  1311→    let contextContent = '';
  1312→    if (task.context_files && task.context_files.length > 0) {
  1313→      for (const pattern of task.context_files) {
  1314→        const matches = await glob(pattern, { cwd: ctx.targetDir, nodir: true });
  1315→        for (const match of matches.slice(0, 50)) { // Limit files
  1316→          const filePath = path.join(ctx.targetDir, match);
  1317→          try {
  1318→            const content = fs.readFileSync(filePath, 'utf-8');
  1319→            contextContent += \`\\n--- File: \${match} ---\\n\${content.slice(0, 5000)}\\n\`;
  1320→          } catch {}
  1321→        }
  1322→      }
  1323→    }
  1324→
  1325→    // Build the prompt
  1326→    const fullPrompt = \`\${task.prompt_template}
  1327→
  1328→## Codebase Context:
  1329→\${contextContent || 'No context files found.'}
  1330→
  1331→## Instructions:
  1332→Respond with a JSON object containing:
  1333→- "scores": an object with category names as keys and numeric scores (1-5) as values
  1334→- "justifications": an object with the same category names as keys and brief explanations as values
  1335→
  1336→Example:
  1337→{
  1338→  "scores": { "architecture": 4, "code-quality": 3, "documentation": 2 },
  1339→  "justifications": { "architecture": "Well-structured...", "code-quality": "Mostly clean...", "documentation": "Lacking..." }
  1340→}
  1341→
  1342→Respond ONLY with the JSON object, no other text.\`;
  1343→
  1344→    try {
  1345→      const client = new Anthropic({ apiKey: ctx.apiKey || process.env.ANTHROPIC_API_KEY });
  1346→
  1347→      const response = await client.messages.create({
  1348→        model,
  1349→        max_tokens: 4096,
  1350→        temperature: 0,
  1351→        messages: [{ role: 'user', content: fullPrompt }],
  1352→      });
  1353→
  1354→      const completedAt = new Date().toISOString();
  1355→      const durationMs = Date.now() - start;
  1356→
  1357→      // Extract token usage
  1358→      const tokenUsage = {
  1359→        inputTokens: response.usage.input_tokens,
  1360→        outputTokens: response.usage.output_tokens,
  1361→        cacheReadTokens: (response.usage as any).cache_read_input_tokens,
  1362→      };
  1363→
  1364→      const estimatedCost = calculateCost(model, tokenUsage);
  1365→
  1366→      // Parse the response
  1367→      const responseText = response.content
  1368→        .filter(c => c.type === 'text')
  1369→        .map(c => (c as any).text)
  1370→        .join('');
  1371→
  1372→      let scores: Record<string, number> = {};
  1373→      let justifications: Record<string, string> = {};
  1374→
  1375→      try {
  1376→        const jsonMatch = responseText.match(/\\{[\\s\\S]*\\}/);
  1377→        if (jsonMatch) {
  1378→          const parsed = JSON.parse(jsonMatch[0]);
  1379→          scores = parsed.scores || {};
  1380→          justifications = parsed.justifications || {};
  1381→        }
  1382→      } catch {
  1383→        return {
  1384→          taskId: task.id, type: task.type, status: 'error',
  1385→          startedAt, completedAt, durationMs,
  1386→          metrics: {}, criteria: {},
  1387→          error: 'Failed to parse LLM judge response as JSON',
  1388→          tokenUsage, estimatedCost,
  1389→        };
  1390→      }
  1391→
  1392→      // Calculate average score
  1393→      const scoreValues = Object.values(scores).filter(v => typeof v === 'number');
  1394→      const averageScore = scoreValues.length > 0
  1395→        ? scoreValues.reduce((a, b) => a + b, 0) / scoreValues.length
  1396→        : 0;
  1397→
  1398→      // Build metrics
  1399→      const metrics: Record<string, number> = { average_score: averageScore };
  1400→      for (const [key, value] of Object.entries(scores)) {
  1401→        metrics[\`score_\${key}\`] = value;
  1402→      }
  1403→
  1404→      // Evaluate criteria
  1405→      const criteria: Record<string, { expected: any; actual: any; passed: boolean }> = {};
  1406→      let allPassed = true;
  1407→
  1408→      if (task.criteria?.min_average_score !== undefined) {
  1409→        const passed = averageScore >= task.criteria.min_average_score;
  1410→        criteria['min_average_score'] = { expected: task.criteria.min_average_score, actual: averageScore, passed };
  1411→        if (!passed) allPassed = false;
  1412→      }
  1413→
  1414→      // Check individual score criteria
  1415→      for (const [key, value] of Object.entries(task.criteria || {})) {
  1416→        if (key.startsWith('min_') && key !== 'min_average_score') {
  1417→          const category = key.slice(4);
  1418→          if (scores[category] !== undefined) {
  1419→            const passed = scores[category] >= value;
  1420→            criteria[key] = { expected: value, actual: scores[category], passed };
  1421→            if (!passed) allPassed = false;
  1422→          }
  1423→        }
  1424→      }
  1425→
  1426→      if (Object.keys(criteria).length === 0) {
  1427→        allPassed = averageScore >= 3.0;
  1428→        criteria['min_average_score'] = { expected: 3.0, actual: averageScore, passed: allPassed };
  1429→      }
  1430→
  1431→      return {
  1432→        taskId: task.id, type: task.type,
  1433→        status: allPassed ? 'pass' : 'fail',
  1434→        startedAt, completedAt, durationMs,
  1435→        metrics, criteria,
  1436→        judgment: { scores, justifications, averageScore },
  1437→        tokenUsage, estimatedCost,
  1438→      };
  1439→    } catch (error) {
  1440→      return {
  1441→        taskId: task.id, type: task.type, status: 'error',
  1442→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1443→        metrics: {}, criteria: {},
  1444→        error: \`LLM Judge failed: \${error instanceof Error ? error.message : String(error)}\`,
  1445→      };
  1446→    }
  1447→  }
  1448→}
  1449→`;
  1450→}
