  1452→export function generateAgentEvalHandler(): string {
  1453→  return `import { spawn } from 'child_process';
  1454→import * as fs from 'fs';
  1455→import * as path from 'path';
  1456→import type { EvalContext } from '../eval-executor.js';
  1457→import type { EvalTask, TaskResult, TaskHandler } from '../task-registry.js';
  1458→
  1459→export class AgentEvalHandler implements TaskHandler {
  1460→  type = 'agent-eval';
  1461→
  1462→  async execute(task: EvalTask, ctx: EvalContext): Promise<TaskResult> {
  1463→    const start = Date.now();
  1464→    const startedAt = new Date().toISOString();
  1465→
  1466→    // Check for Python and Docker availability
  1467→    const pythonAvailable = await this.checkCommand('python3 --version');
  1468→    const dockerAvailable = await this.checkCommand('docker info');
  1469→
  1470→    if (!pythonAvailable || !dockerAvailable) {
  1471→      return {
  1472→        taskId: task.id, type: task.type, status: 'skip',
  1473→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1474→        metrics: {}, criteria: {},
  1475→        error: \`\${!pythonAvailable ? 'Python' : 'Docker'} not available. Agent-eval requires both Python and Docker.\`,
  1476→      };
  1477→    }
  1478→
  1479→    // Check for harness directory
  1480→    const harnessDir = path.join(ctx.workingDir, 'harness');
  1481→    if (!fs.existsSync(path.join(harnessDir, 'run_task.py'))) {
  1482→      return {
  1483→        taskId: task.id, type: task.type, status: 'error',
  1484→        startedAt, completedAt: new Date().toISOString(), durationMs: Date.now() - start,
  1485→        metrics: {}, criteria: {},
  1486→        error: 'harness/run_task.py not found. Ensure the Python harness is set up.',
  1487→      };
  1488→    }
  1489→
  1490→    const model = task.model || 'claude-sonnet-4-20250514';
  1491→    const maxTokens = task.max_tokens || 200000;
  1492→    const timeout = task.timeout || 600;
  1493→
  1494→    try {
  1495→      // Run the Python harness
  1496→      const result = await this.runPythonHarness({
  1497→        harnessDir,
  1498→        model,
  1499→        maxTokens,
  1500→        timeout,
  1501→        dataset: task.config?.dataset || 'princeton-nlp/SWE-bench_Verified',
  1502→        subset: task.config?.subset || 20,
  1503→        dockerRegistry: task.docker_registry || 'ghcr.io/epoch-research',
  1504→        apiKey: ctx.apiKey,
  1505→        outputDir: path.join(ctx.workingDir, '.eval-runs', ctx.runId, 'predictions'),
  1506→      });
  1507→
  1508→      const completedAt = new Date().toISOString();
  1509→      const durationMs = Date.now() - start;
  1510→
  1511→      // Parse predictions output
  1512→      let predictions: Array<{ instanceId: string; patch: string; resolved: boolean }> = [];
