  1592→    apiKey?: string;
  1593→    outputDir: string;
  1594→  }): Promise<{ exitCode: number; stdout: string; stderr: string; tokenUsage?: any; estimatedCost?: any }> {
  1595→    return new Promise((resolve) => {
  1596→      const args = [
  1597→        'run_task.py',
  1598→        '--model', options.model,
  1599→        '--max-tokens', String(options.maxTokens),
  1600→        '--dataset', options.dataset,
  1601→        '--subset', String(options.subset),
  1602→        '--docker-registry', options.dockerRegistry,
  1603→        '--output-dir', options.outputDir,
  1604→      ];
  1605→
  1606→      const env = { ...process.env };
  1607→      if (options.apiKey) {
  1608→        env['ANTHROPIC_API_KEY'] = options.apiKey;
  1609→      }
  1610→
  1611→      const child = spawn('python3', args, {
  1612→        cwd: options.harnessDir,
  1613→        stdio: ['ignore', 'pipe', 'pipe'],
  1614→        env,
  1615→      });
  1616→
  1617→      let stdout = '';
  1618→      let stderr = '';
  1619→
  1620→      child.stdout.on('data', (data: Buffer) => { stdout += data.toString(); });
  1621→      child.stderr.on('data', (data: Buffer) => { stderr += data.toString(); });
  1622→
  1623→      const timer = setTimeout(() => {
  1624→        child.kill('SIGTERM');
  1625→        resolve({ exitCode: 124, stdout, stderr: stderr + '\\nProcess timed out' });
  1626→      }, options.timeout * 1000);
  1627→
  1628→      child.on('close', (code: number | null) => {
  1629→        clearTimeout(timer);
  1630→
  1631→        // Try to extract token usage and cost from stdout (last JSON line)
  1632→        let tokenUsage: any;
  1633→        let estimatedCost: any;
  1634→        try {
  1635→          const lastLine = stdout.trim().split('\\n').pop();
  1636→          if (lastLine) {
  1637→            const parsed = JSON.parse(lastLine);
  1638→            tokenUsage = parsed.token_usage;
  1639→            estimatedCost = parsed.estimated_cost;
  1640→          }
  1641→        } catch {}
  1642→
  1643→        resolve({ exitCode: code ?? 1, stdout, stderr, tokenUsage, estimatedCost });
  1644→      });
  1645→
  1646→      child.on('error', (err: Error) => {
  1647→        clearTimeout(timer);
  1648→        resolve({ exitCode: 1, stdout, stderr: err.message });
  1649→      });
  1650→    });
  1651→  }
  1652→}
