  2079→    """Execute a bash command in the Docker container."""
  2080→    try:
  2081→        result = subprocess.run(
  2082→            ['docker', 'exec', container_id, 'bash', '-c', command],
  2083→            capture_output=True, text=True, timeout=120,
  2084→        )
  2085→        output = ''
  2086→        if result.stdout:
