  2133→        if count > 1:
  2134→            return f'Error: old_str found {count} times in {path}. Must match exactly once.'
  2135→
  2136→        # Use Python inside the container for reliable replacement
  2137→        py_cmd = f\"\"\"python3 -c "
  2138→import sys
  2139→path = '{path}'
  2140→with open(path) as f:
  2141→    content = f.read()
  2142→old = '''{_escape_triple_quotes(old_str)}'''
  2143→new = '''{_escape_triple_quotes(new_str)}'''
  2144→content = content.replace(old, new, 1)
  2145→with open(path, 'w') as f:
  2146→    f.write(content)
  2147→print('OK')
  2148→"\"\"\"
  2149→        return _execute_bash(py_cmd, container_id)
  2150→
  2151→    elif command == 'insert':
  2152→        insert_line = tool_input.get('insert_line', 0)
  2153→        new_str = tool_input.get('new_str', '')
  2154→        escaped = new_str.replace("'", "'\\\\''")
  2155→        cmd = f"sed -i '{insert_line}a\\\\{escaped}' '{path}'"
  2156→        return _execute_bash(cmd, container_id)
  2157→
  2158→    else:
  2159→        return f'Unknown editor command: {command}'
  2160→
  2161→
  2162→def _escape_for_shell(s: str) -> str:
  2163→    return s.replace("'", "'\\\\''")
  2164→
  2165→
  2166→def _escape_triple_quotes(s: str) -> str:
  2167→    return s.replace("'''", "'\\\\'\\\\'\\\\'")
  2168→`,
