import subprocess
from typing import Any


def get_tool_definitions() -> list:
    """Return tool definitions for the Anthropic API."""
    return [
        {
            'name': 'bash',
            'description': 'Execute a bash command in the container. Use for running tests, exploring files, etc.',
            'input_schema': {
                'type': 'object',
                'properties': {
                    'command': {
