                'properties': {
                    'command': {
                        'type': 'string',
                        'enum': ['view', 'create', 'str_replace', 'insert'],
                        'description': 'The operation to perform',
                    },
                    'path': {
                        'type': 'string',
                        'description': 'Absolute path to the file (must start with /testbed/)',
