    expect(spec.name).toBe('test-eval');
    expect(spec.tasks).toHaveLength(1);
  });

  it('throws on non-existent file', () => {
    expect(() => parser.parse('/nonexistent/spec.yaml')).toThrow('Spec file not found');
  });

  it('throws on unsupported extension', () => {
