                    tool_results.append({
                        'type': 'tool_result',
                        'tool_use_id': block.id,
                        'content': result[:30000],  # Truncate output
                    })

            messages.append({'role': 'user', 'content': tool_results})

        return {
            'input_tokens': self.total_input_tokens,
            'output_tokens': self.total_output_tokens,
        }
