  }` : ''}${hasCommands ? `

  // Command execution helpers
  async runCommand(command: string): Promise<void> {
    const result = await this.commandRunner.execute(command);
    console.log(this.commandRunner.formatResult(result));
  }` : ''}${hasWeb ? `

