// Helper function to get the correct API key environment variable name for each provider
function getApiKeyEnvVar(provider: string | undefined): string {
  switch (provider) {
    case 'claude':
      return 'ANTHROPIC_API_KEY';
    case 'openai':
      return 'OPENAI_API_KEY';
    case 'huggingface':
