    ${hasKnowledge ? `
    const knowledgeToolsEnabled = new Set(${JSON.stringify(enabledTools.filter(t => KNOWLEDGE_TOOL_IDS.includes(t.id)).map(t => t.id))});

    if (knowledgeToolsEnabled.has('doc-ingest')) {
