## MCP Server Capabilities

${(config.mcpServers || []).filter(s => s.enabled).map(s => `- **${s.name}**: ${s.description || 'MCP server for extended capabilities'}`).join('\n') || '- No MCP servers configured'}
`
}

function generateTinyAgentReadme(
  config: AgentConfig,
